const rpc = $input.first().json;
if (rpc.error) throw new Error('MCP transport error: ' + JSON.stringify(rpc.error));
if (rpc.result && rpc.result.isError) throw new Error('MCP tool error: ' + ((rpc.result.content && rpc.result.content[0] && rpc.result.content[0].text) || 'unknown'));
// The slot JSON arrives as text inside the MCP tool result.
const slot = JSON.parse(rpc.result.content[0].text);
if (slot.error) throw new Error('request_file_upload: ' + slot.error);
const trigger = $('On form submission').first();
const binKey = Object.keys(trigger.binary || {})[0];
if (!binKey) throw new Error('No file arrived from the form.');
// Ready-made JSON-RPC body for the Open PDF node (building it here avoids
// n8n's expression parser tripping on `}}` inside inline object literals).
slot.openBody = {
  jsonrpc: '2.0', id: 2, method: 'tools/call',
  params: { name: 'open_pdf', arguments: { upload_token: slot.upload_token } },
};
return [{ json: slot, binary: { file: trigger.binary[binKey] } }];

const rpc = $input.first().json;
if (rpc.error) throw new Error('MCP transport error: ' + JSON.stringify(rpc.error));
if (rpc.result && rpc.result.isError) throw new Error('MCP tool error: ' + ((rpc.result.content && rpc.result.content[0] && rpc.result.content[0].text) || 'unknown'));
const ws = JSON.parse(rpc.result.content[0].text);
if (ws.error) throw new Error('open_pdf: ' + ws.error);

const raw = $('On form submission').first().json['Data JSON'];
let data;
try { data = JSON.parse(raw); }
catch (e) { throw new Error('Data JSON must be valid JSON, e.g. {"age_score": "1"}'); }

// Match data keys to template field names (case/punctuation-insensitive).
const norm = s => String(s).toLowerCase().replace(/[^a-z0-9]+/g, '');
const values = {}, unmatched = [];
for (const [k, v] of Object.entries(data)) {
  const nk = norm(k);
  const f = ws.fields.find(f => norm(f.name) === nk)
    || ws.fields.find(f => f.name && (norm(f.name).includes(nk) || nk.includes(norm(f.name))));
  if (f) values[f.id] = String(v); else unmatched.push(k);
}

if (!Object.keys(values).length) {
  const named = ws.fields.filter(f => f.name).map(f => f.name);
  throw new Error(named.length
    ? 'No data keys matched the template fields. Available: ' + named.join(', ')
    : 'This PDF has no saved template with named fields. Open it once with an AI agent (Claude/Cursor + justfill MCP), name the fields and save_template — then this workflow runs deterministically.');
}

return [{ json: {
  workspace_id: ws.summary.workspace_id,
  source: ws.summary.source,
  matched: Object.keys(values).length,
  unmatched,
  values,
  fillBody: {
    jsonrpc: '2.0', id: 3, method: 'tools/call',
    params: { name: 'fill_pdf', arguments: { workspace_id: ws.summary.workspace_id, values } },
  },
} }];

const rpc = $input.first().json;
if (rpc.error) throw new Error('MCP transport error: ' + JSON.stringify(rpc.error));
if (rpc.result && rpc.result.isError) throw new Error('MCP tool error: ' + ((rpc.result.content && rpc.result.content[0] && rpc.result.content[0].text) || 'unknown'));
const out = JSON.parse(rpc.result.content[0].text);
if (out.error) throw new Error('fill_pdf: ' + out.error);
// download_url: plain GET, no auth, valid until the workspace expires (~24h).
return [{ json: {
  download_url: out.download_url,
  output_mode: out.output_mode,
  filled_fields: out.filled_fields,
  link_expires_at: out.link_expires_at,
  warnings: out.warnings || null,
} }];
